import { Component } from '@angular/core';
import { DrawerService } from '../../services/drawer.service';
import { PrimeIcons, MenuItem } from 'primeng/api';

@Component({
  selector: 'app-drawer',
  standalone: true,
  templateUrl: './drawer.component.html',
  styleUrls: ['./drawer.component.css'],
})
export class DrawerComponent {
  _visible = false;
  shortcuts: any;
  youList: any;
  exploreList:any;
  subscription: { label: string; icon: string }[];
  constructor(private drawerService: DrawerService) {
    this.drawerService.visible$.subscribe((v) => {
      this._visible = v;
    });
    this.shortcuts = [
      {
        isActive: true,
        label: 'Home',
        icon: PrimeIcons.HOME,
      },
      {
        isActive: false,
        label: 'Sorts',
        icon: PrimeIcons.PLAY,
      },
    ];

    this.youList = [
      {
        label: 'Your channel',
        icon: PrimeIcons.USER,
      },
      {
        label: 'History',
        icon: PrimeIcons.HISTORY,
      },
      {
        label: 'Playlists',
        icon: PrimeIcons.PLAY,
      },
      {
        label: 'Watch later',
        icon: PrimeIcons.CLOCK,
      },
      {
        label: 'Liked videos',
        icon: PrimeIcons.THUMBS_UP,
      },
      {
        label: 'Downloads',
        icon: PrimeIcons.DOWNLOAD,
      },
    ];
     this.exploreList = [
      {
        label: 'Shopping',
        icon: PrimeIcons.SHOPPING_BAG,
      },
      {
        label: 'Music',
        icon: PrimeIcons.TIKTOK,
      },
      {
        label: 'Films',
        icon: PrimeIcons.VIDEO,
      },
      {
        label: 'Live',
        icon: PrimeIcons.MEGAPHONE,
      },
      {
        label: 'Gaming',
        icon: PrimeIcons.THUMBS_UP,
      },
      {
        label: 'news',
        icon: PrimeIcons.REDDIT,
      },
      {
        label: 'Sport',
        icon: PrimeIcons.TROPHY,
      },
      {
        label: 'Courses',
        icon: PrimeIcons.BOOK,
      },
    ];

    this.subscription = [
      {
        label: 'Tv9 Kannada',
        icon: 'assets/channels/tv9.jpg',
      },
      {
        label: 'Tv9 Telagu',
        icon: 'assets/channels/tv9.jpg',
      },
      {
        label: 'Public Tv',
        icon: 'assets/channels/public.jpg',
      },
      {
        label: 'Tv9 Kannada',
        icon: 'assets/channels/tv9.jpg',
      },
      {
        label: 'Tv9 Telagu',
        icon: 'assets/channels/tv9.jpg',
      },
      {
        label: 'Public Tv',
        icon: 'assets/channels/public.jpg',
      },
      {
        label: 'Tv9 Kannada',
        icon: 'assets/channels/tv9.jpg',
      },
      {
        label: 'Tv9 Telagu',
        icon: 'assets/channels/tv9.jpg',
      },
      {
        label: 'Public Tv',
        icon: 'assets/channels/public.jpg',
      },
      {
        label: 'Tv9 Kannada',
        icon: 'assets/channels/tv9.jpg',
      },
      {
        label: 'Tv9 Telagu',
        icon: 'assets/channels/tv9.jpg',
      },
      {
        label: 'Public Tv',
        icon: 'assets/channels/public.jpg',
      },
    ];
  }

  showAll = false;

  get visibleItems() {
    return this.showAll ? this.subscription : this.subscription.slice(0, 4);
  }

  toggleItems() {
    this.showAll = !this.showAll;
  }

   showAllExplore = false;

  get visibleExploreItems() {
    return this.showAllExplore ? this.exploreList : this.exploreList.slice(0, 4);
  }

  toggleExploreItems() {
    this.showAllExplore = !this.showAllExplore;
  }
}

@if (_visible) {
<div class="ytb-leftDrawer" [class.open]="_visible">
  <div class="ytb-leftDrawer__container">
    <div class="ytb-shortcut mb-4 divider">
      @for (item of shortcuts; track item.label) {
      <a class="ytb-shortcut__item d-flex align-items-center" [class.active]="item.isActive" href="#">
        <i class="icon" [class]="item.icon"></i>
        <span class="f-14">{{ item.label }}</span>
      </a>
      }
    </div>


    <div class="ytb-subscription mb-4 divider">
      @for (item of visibleItems; track item.label) {
      <a class="ytb-subscription__item d-flex align-items-center" href="#">
        <img class="icon" [src]="item.icon" alt="icon">
        <span class="f-14">{{ item.label }}</span>
      </a>
      }

      <button (click)="toggleItems()" class="showItems-btn">
        <i class="pi" [class.pi-angle-up]="showAll" [class.pi-angle-down]="!showAll">
        </i>
        {{ showAll ? 'Show Less' : 'Show More' }}
      </button>
    </div>



    <div class="ytb-youList mb-4 divider">
      <h2 class="f-16 fw-medium">You</h2>
      @for (item of youList; track item.label) {
      <a class="ytb-youList__item d-flex align-items-center" href="#">
        <i class="icon" [class]="item.icon"></i>
        <span class="f-14">{{ item.label }}</span>
      </a>
      }
    </div>



    <div class="ytb-youList mb-4 divider">
      <h2 class="f-16 fw-medium">Explore</h2>
      @for (item of visibleExploreItems; track item.label) {
      <a class="ytb-youList__item d-flex align-items-center" href="#">
        <i class="icon" [class]="item.icon"></i>
        <span class="f-14">{{ item.label }}</span>
      </a>
      }

      <button (click)="toggleExploreItems()" class="showItems-btn">
        <i class="pi" [class.pi-angle-up]="showAllExplore" [class.pi-angle-down]="!showAllExplore">
        </i>
        {{ showAllExplore ? 'Show Less' : 'Show More' }}
      </button>
    </div>
     <a class="ytb-term f-13 mb-4 d-block" href="#">
    TermsPrivacyPolicy & SafetyHow YouTube worksTest new features
  </a>
  <span class="f-12 ytb-gllc d-block">© 2026 Google LLC</span>

  </div>



</div>
}
